parameters.functionCode:
const claudeResponse = $input.first().json;
const intent = claudeResponse.content[0].text.trim();
const emailData = $('Gmail - New Email').first().json;

const validIntents = ['NEW_CLIENT_INTAKE', 'EXISTING_CLIENT_QUESTION', 'COURT_NOTICE', 'OPPOSING_COUNSEL', 'SPAM', 'GENERAL_INQUIRY'];
const classifiedIntent = validIntents.find(i => intent.includes(i)) || 'GENERAL_INQUIRY';

return [{json: {...emailData, intent: classifiedIntent}}];

